8861 VPlanPtr LoopVectorizationPlanner::buildVPlan(VFRange &Range) {
8862   // Outer loop handling: They may require CFG and instruction level
8863   // transformations before even evaluating whether vectorization is profitable.
8864   // Since we cannot modify the incoming IR, we need to build VPlan upfront in
8865   // the vectorization pipeline.
8866   assert(!OrigLoop->isInnermost());
8867   assert(EnableVPlanNativePath && "VPlan-native path is not enabled.");
8868 
8869   // Create new empty VPlan
8870   auto Plan = VPlan::createInitialVPlan(
8871       createTripCountSCEV(Legal->getWidestInductionType(), PSE, OrigLoop),
8872       *PSE.getSE());
8873 
8874   // Build hierarchical CFG
8875   VPlanHCFGBuilder HCFGBuilder(OrigLoop, LI, *Plan);
8876   HCFGBuilder.buildHierarchicalCFG();
8877 
8878   for (ElementCount VF : Range)
8879     Plan->addVF(VF);
8880 
8881   VPlanTransforms::VPInstructionsToVPRecipes(
8882       Plan,
8883       [this](PHINode *P) { return Legal->getIntOrFpInductionDescriptor(P); },
8884       *PSE.getSE(), *TLI);
8885 
8886   // Remove the existing terminator of the exiting block of the top-most region.
8887   // A BranchOnCount will be added instead when adding the canonical IV recipes.
8888   auto *Term =
8889       Plan->getVectorLoopRegion()->getExitingBasicBlock()->getTerminator();
8890   Term->eraseFromParent();
8891 
8892   // Tail folding is not supported for outer loops, so the induction increment
8893   // is guaranteed to not wrap.
8894   bool HasNUW = true;
8895   addCanonicalIVRecipes(*Plan, Legal->getWidestInductionType(), HasNUW,
8896                         DebugLoc());
8897   assert(verifyVPlanIsValid(*Plan) && "VPlan is invalid");
