8964     // Collect the chain of "link" recipes for the reduction starting at PhiR.
8965     SetVector<VPSingleDefRecipe *> Worklist;
8966     Worklist.insert(PhiR);
8967     for (unsigned I = 0; I != Worklist.size(); ++I) {
8968       VPSingleDefRecipe *Cur = Worklist[I];
